using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;
using System.Threading.Tasks;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain any leftover notifications from prior tests (static queue)
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectCreateMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("System", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectUpdateMessage()
        {
            _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectDeleteMessage()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", null, EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", "   ", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin@test.com");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("admin@test.com", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
            Assert.AreEqual("C", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, just verify it doesn't throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(0);
            _sut.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _sut.Dispose();
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_MultipleNotifications_AllQueued()
        {
            for (int i = 0; i < 20; i++)
            {
                _sut.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            var received = new List<Notification>();
            Notification n;
            while ((n = _sut.ReceiveNotification()) != null)
            {
                received.Add(n);
            }

            Assert.AreEqual(20, received.Count);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list.ToList());
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(5, true, DisplayName = "Later page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 10, 10, true, DisplayName = "First page of many has next")]
        [DataRow(10, 100, 10, false, DisplayName = "Last page has no next")]
        [DataRow(5, 100, 10, true, DisplayName = "Middle page has next")]
        [DataRow(1, 5, 10, false, DisplayName = "Single page has no next")]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalCount, int pageSize, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
        [DataRow(9, 3, 3, DisplayName = "9 items, page size 3 = 3 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
        public void TotalPages_CalculatedCorrectly(int totalCount, int pageSize, int expectedPages)
        {
            var list = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);

            Assert.AreEqual(expectedPages, list.TotalPages);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfData()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10) = 3
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page[0]); // First item on page 2
            Assert.AreEqual(20, page[9]); // Last item on page 2
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 3);

            Assert.AreEqual(1, page.PageIndex);
            Assert.AreEqual(3, page.Count);
            CollectionAssert.AreEqual(new[] { 1, 2, 3 }, page.ToList());
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 3);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(2, page.Count);
            CollectionAssert.AreEqual(new[] { 4, 5 }, page.ToList());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, page.Count);
            Assert.AreEqual(0, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_NoNextOrPrevious()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, page.PageIndex);
            Assert.AreEqual(1, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
            Assert.AreEqual(5, page.Count);
        }
    }
}

