{"file_text": "using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list.ToList());
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(5, true, DisplayName = "Later page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 10, 10, true, DisplayName = "First page of many has next")]
        [DataRow(10, 100, 10, false, DisplayName = "Last page has no next")]
        [DataRow(5, 100, 10, true, DisplayName = "Middle page has next")]
        [DataRow(1, 5, 10, false, DisplayName = "Single page has no next")]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalCount, int pageSize, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
        [DataRow(9, 3, 3, DisplayName = "9 items, page size 3 = 3 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
        public void TotalPages_CalculatedCorrectly(int totalCount, int pageSize, int expectedPages)
        {
            var list = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);

            Assert.AreEqual(expectedPages, list.TotalPages);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfData()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10) = 3
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page[0]); // First item on page 2
            Assert.AreEqual(20, page[9]); // Last item on page 2
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 3);

            Assert.AreEqual(1, page.PageIndex);
            Assert.AreEqual(3, page.Count);
            CollectionAssert.AreEqual(new[] { 1, 2, 3 }, page.ToList());
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 3);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(2, page.Count);
            CollectionAssert.AreEqual(new[] { 4, 5 }, page.ToList());
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, page.Count);
            Assert.AreEqual(0, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_NoNextOrPrevious()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, page.PageIndex);
            Assert.AreEqual(1, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
            Assert.AreEqual(5, page.Count);
        }
    }
}
