using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;
using System.Threading.Tasks;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain any leftover notifications from prior tests (static queue)
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectCreateMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("System", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectUpdateMessage()
        {
            _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectDeleteMessage()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", null, EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "99", "   ", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin@test.com");

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("admin@test.com", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
            Assert.AreEqual("C", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, just verify it doesn't throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(0);
            _sut.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _sut.Dispose();
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_MultipleNotifications_AllQueued()
        {
            for (int i = 0; i < 20; i++)
            {
                _sut.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            var received = new List<Notification>();
            Notification n;
            while ((n = _sut.ReceiveNotification()) != null)
            {
                received.Add(n);
            }

            Assert.AreEqual(20, received.Count);
        }
    }
}

