using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain static queue
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _context = TestDbContextFactory.CreateSeeded();
            _sut = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _sut.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _sut.GetNotifications();

            Assert.IsNotNull(result);
            var json = result.Value;
            Assert.IsNotNull(json);
            // Verify success property via dynamic
            var type = json.GetType();
            var successProp = type.GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(json));
            var countProp = type.GetProperty("count");
            Assert.AreEqual(0, (int)countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotificationsInQueue()
        {
            // Enqueue some notifications via the notification service on the controller
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var result = _sut.GetNotifications();

            var json = result.Value;
            var type = json.GetType();
            var countProp = type.GetProperty("count");
            Assert.AreEqual(2, (int)countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            var result = _sut.GetNotifications();

            var json = result.Value;
            var type = json.GetType();
            var countProp = type.GetProperty("count");
            Assert.AreEqual(10, (int)countProp.GetValue(json));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _sut.MarkAsRead(1);

            var json = result.Value;
            var type = json.GetType();
            var successProp = type.GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(json));
        }
    }
}

