        [TestInitialize]
        public void Setup()
        {
            // Drain static queue
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _context = TestDbContextFactory.CreateSeeded();
            _sut = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

