namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _sut.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            var result = _sut.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // 3 students with 3 different enrollment dates in seed data
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _sut.About() as ViewResult;
            var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;

            // Each date group should have correct student count
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.AreEqual(3, totalStudents);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _sut.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _sut.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _sut.Error();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _sut.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _sut.ViewBag.Message);
        }
    }
}

