using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParams_ReturnsAllStudentsSortedByLastName()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            // Default sort is by LastName ascending
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsSortedDescending()
        {
            var result = _sut.Index("name_desc", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alexander", model[model.Count - 1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsSortedByDateAscending()
        {
            var result = _sut.Index("Date", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.IsTrue(model[0].EnrollmentDate <= model[1].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsSortedByDateDescending()
        {
            var result = _sut.Index("date_desc", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.IsTrue(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _sut.Index(null, null, "Alexander", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _sut.Index(null, null, "Meredith", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alonso", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchNoMatch_ReturnsEmptyList()
        {
            var result = _sut.Index(null, null, "ZZZ_NoMatch", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Index_SearchStringResetsPage()
        {
            var result = _sut.Index(null, null, "A", 3) as ViewResult;

            // When searchString is not null, page is reset to 1
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _sut.Index(null, "Carson", null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParams()
        {
            _sut.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithNameDescSort_SetsViewBagSortParamsCorrectly()
        {
            _sut.Index("name_desc", null, null, null);

            Assert.AreEqual("", _sut.ViewBag.NameSortParm);
        }

        [TestMethod]
        public void Index_WithDateSort_SetsDateDescSortParm()
        {
            _sut.Index("Date", null, null, null);

            Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 9, 1)
