using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context;
        private DepartmentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _sut.Details(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var dept = result.Model as Department;
            Assert.AreEqual("English", dept.Name);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsView()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 1
            };

            var result = _sut.Create(dept) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidDepartment_SavesInDb()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 1
            };

            _sut.Create(dept);

            var saved = _context.Departments.FirstOrDefault(d => d.Name == "Science");
            Assert.IsNotNull(saved);
            Assert.AreEqual(200000, saved.Budget);
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _sut.Create(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Edit(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            var dept = result.Model as Department;
            Assert.AreEqual("English", dept.Name);
        }

        [TestMethod]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.AsNoTracking().First(d => d.DepartmentID == 1);
            dept.Name = "Updated English";

            var result = _sut.Edit(dept) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_POST_ValidDepartment_UpdatesDb()
        {
            var dept = _context.Departments.AsNoTracking().First(d => d.DepartmentID == 1);
            dept.Name = "Updated English";

            _sut.Edit(dept);

            var updated = _context.Departments.AsNoTracking().First(d => d.DepartmentID == 1);
            Assert.AreEqual("Updated English", updated.Name);
        }

        [TestMethod]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.AsNoTracking().First();

            var result = _sut.Edit(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Delete(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var dept = result.Model as Department;
            Assert.AreEqual("English", dept.Name);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsNull(_context.Departments.Find(1));
        }

        #endregion
    }
}

