using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Http;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _sut;
        private Mock<IWebHostEnvironment> _envMock;
        private Mock<ILogger<CoursesController>> _loggerMock;
        private string _tempDir;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _sut.Details(1050) as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.AreEqual("Chemistry", course.Title);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithEmptyCourse()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.IsNotNull(course);
            Assert.IsNotNull(_sut.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Create_POST_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _sut.Create(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidCourse_NoImage_SavesInDb()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            _sut.Create(course, null);

            var saved = _context.Courses.Find(9999);
            Assert.IsNotNull(saved);
            Assert.AreEqual("New Course", saved.Title);
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _sut.Create(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_POST_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _sut.Create(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB, over 5MB limit

            var result = _sut.Create(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_POST_ValidImage_SavesFileAndSetsPath()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _sut.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var saved = _context.Courses.Find(9999);
            Assert.IsTrue(saved.TeachingMaterialImagePath.StartsWith("/Uploads/TeachingMaterials/"));
        }

        [TestMethod]
        [DataRow(".jpg")]
        [DataRow(".jpeg")]
        [DataRow(".png")]
        [DataRow(".gif")]
        [DataRow(".bmp")]
        public void Create_POST_AllowedExtensions_Accepted(string ext)
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "ExtTest",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns($"test{ext}");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _sut.Create(course, fileMock.Object);

            Assert.IsInstanceOfType<RedirectToActionResult>(result);
            // Clean up for next test
            _context.Courses.Remove(_context.Courses.Find(8888));
            _context.SaveChanges();
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Edit(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            var result = _sut.Edit(1050) as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.AreEqual("Chemistry", course.Title);
        }

        [TestMethod]
        public void Edit_POST_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _sut.Edit(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_POST_ValidCourse_UpdatesDb()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            _sut.Edit(course, null);

            var updated = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            Assert.AreEqual("Updated Chemistry", updated.Title);
        }

        [TestMethod]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = _context.Courses.AsNoTracking().First();

            var result = _sut.Edit(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_POST_InvalidExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.pdf");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _sut.Edit(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_POST_FileTooLarge_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024);

            var result = _sut.Edit(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithCourse()
        {
            var result = _sut.Delete(1050) as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.AreEqual("Chemistry", course.Title);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var result = _sut.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsNull(_context.Courses.Find(1050));
        }

        #endregion
    }
}

