using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            var result = _sut.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_ShowsCoursesForInstructor()
        {
            var result = _sut.Index(1, null) as ViewResult;

            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.IsTrue(model.Courses.Any());
        }

        [TestMethod]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var result = _sut.Index(1, 1050) as ViewResult;

            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Enrollments);
        }

        [TestMethod]
        public void Index_SetsViewBagInstructorID()
        {
            _sut.Index(1, null);

            Assert.AreEqual(1, _sut.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_SetsViewBagCourseID()
        {
            _sut.Index(1, 1050);

            Assert.AreEqual(1050, _sut.ViewBag.CourseID);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _sut.Details(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Create

        [TestMethod]
        public void Create_GET_ReturnsViewWithNewInstructor()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_POST_ValidInstructor_NoCourses_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _sut.Create(instructor, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_POST_ValidInstructor_SavesInDb()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            _sut.Create(instructor, null);

            var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "NewInstructor");
            Assert.IsNotNull(saved);
        }

        [TestMethod]
        public void Create_POST_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            _sut.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "WithCourses");
            Assert.IsNotNull(saved);
            Assert.AreEqual(2, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor();

            var result = _sut.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null);

            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Delete(9999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _sut.DeleteConfirmed(2) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsNull(_context.Instructors.Find(2));
        }

        [TestMethod]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Instructor 1 is admin of dept 1
            _sut.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.IsNull(dept.InstructorID);
        }

        #endregion
    }
}

