using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_SeedsStudents()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_SeedsInstructors()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_SeedsDepartments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCourses()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCourseAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_SeedsEnrollments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_CalledTwice_DoesNotDuplicateData()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_StudentHasCorrectName()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var student = context.Students.First(s => s.LastName == "Alexander");
            Assert.AreEqual("Carson", student.FirstMidName);
        }

        [TestMethod]
        public void Initialize_DepartmentHasAdministrator()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var dept = context.Departments.First(d => d.Name == "English");
            Assert.IsNotNull(dept.InstructorID);
        }

        [TestMethod]
        public void Initialize_EnrollmentHasGrade()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var enrollmentWithGrade = context.Enrollments.First(e => e.Grade != null);
            Assert.IsNotNull(enrollmentWithGrade.Grade);
        }

        [TestMethod]
        public void Initialize_EnrollmentCanHaveNoGrade()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var enrollmentNoGrade = context.Enrollments.FirstOrDefault(e => e.Grade == null);
            Assert.IsNotNull(enrollmentNoGrade);
        }
    }

    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void Context_HasAllDbSets()
        {
            using var context = TestDbContextFactory.Create();

            Assert.IsNotNull(context.Courses);
            Assert.IsNotNull(context.Enrollments);
            Assert.IsNotNull(context.Departments);
            Assert.IsNotNull(context.OfficeAssignments);
